customColumn1.onClick:
{{
(() => {
  // 1) Captura fila de la tabla de Facturadas
  const row = Informacion_tablaF.triggeredRow || Informacion_tablaF.selectedRow;
  if (!row) { showAlert("No hay datos en la factura seleccionada.", "warning"); return; }

  // 2) Limpiar y guardar en facturaSel
  storeValue("facturaSel", null, true);
  storeValue("facturaSel", row, true);

  // 3) Abrir modal de Facturadas
  resetWidget("Modal_Facturadas", true);
  showModal("Modal_Facturadas");
})();
}}
